import lief

binary = lief.MachO.parse("_.dwarf")
macho = binary.at(0)

# Get symbol table - look up by address
offsets = [0x3e1700, 0x2615fc, 0x16c31c, 0x16c620, 0x18b678, 0x49cc]

# Collect all symbols with their addresses
symbols = []
for sym in macho.symbols:
    if sym.value > 0:
        symbols.append((sym.value, sym.name))

symbols.sort(key=lambda x: x[0])

# For each offset, find the closest symbol before it
for offset in offsets:
    best = None
    for addr, name in symbols:
        if addr <= offset:
            best = (addr, name)
        else:
            break
    if best:
        print(f"  0x{offset:08x} -> {best[1]} + 0x{offset - best[0]:x}")
    else:
        print(f"  0x{offset:08x} -> (no symbol found)")
